const childWorkflows = ['CWF-110', 'CWF-120', 'CWF-130', 'CWF-140'];
let executionPlan = { workflows_to_execute: childWorkflows, current_index: 0, status: 'PLANNING', decisions: {} };
return [{ json: { ...$json, execution_plan: executionPlan, pack_orchestration: { started_at: new Date().toISOString(), expected_duration_seconds: 120 } } }];

// Capture node for cwf110_result
// $json here = the output of the immediately preceding Execute CWF-110 node
const subOutput = $json || {};

// Restore parent context from Execution Planner Node (preserves dossier_id, route_id, pack_context, etc.)
let parentCtx = {};
try { parentCtx = $('Execution Planner Node').first().json || {}; } catch(e) {}

const acc = { ...parentCtx };

// Pull prior captures so accumulated state survives across the chain


// Add this node's capture
acc["cwf110_result"] = {
  status: subOutput.status || 'SUCCESS',
  payload: subOutput.payload || subOutput,
  captured_at: new Date().toISOString()
};

return [{ json: acc }];

// Capture node for cwf120_result
// $json here = the output of the immediately preceding Execute CWF-120 node
const subOutput = $json || {};

// Restore parent context from Execution Planner Node (preserves dossier_id, route_id, pack_context, etc.)
let parentCtx = {};
try { parentCtx = $('Execution Planner Node').first().json || {}; } catch(e) {}

const acc = { ...parentCtx };

// Pull prior captures so accumulated state survives across the chain
try { const c = $('Capture CWF-110 Result').first(); if (c) acc["cwf110_result"] = c.json["cwf110_result"] || c.json; } catch(e) {}

// Add this node's capture
acc["cwf120_result"] = {
  status: subOutput.status || 'SUCCESS',
  payload: subOutput.payload || subOutput,
  captured_at: new Date().toISOString()
};

return [{ json: acc }];

