// Restore parent context from Execution Planner Node (preserves dossier_id, route_id, pack_context, etc.)
let parentCtx = {};
try { parentCtx = $('Execution Planner Node').first().json || {}; } catch(e) {}

const acc = { ...parentCtx };

// Pull prior captures so accumulated state survives across the chain
try { const c = $('Capture CWF-110 Result').first(); if (c) acc["cwf110_result"] = c.json["cwf110_result"] || c.json; } catch(e) {}
  try { const c = $('Capture CWF-120 Result').first(); if (c) acc["cwf120_result"] = c.json["cwf120_result"] || c.json; } catch(e) {}

// Add this node's capture
acc["cwf130_result"] = {
