return [{ json: acc }];

// Capture node for cwf140_result
// $json here = the output of the immediately preceding Execute CWF-140 node
const subOutput = $json || {};

// Restore parent context from Execution Planner Node (preserves dossier_id, route_id, pack_context, etc.)
let parentCtx = {};
try { parentCtx = $('Execution Planner Node').first().json || {}; } catch(e) {}

const acc = { ...parentCtx };

// Pull prior captures so accumulated state survives across the chain
try { const c = $('Capture CWF-110 Result').first(); if (c) acc["cwf110_result"] = c.json["cwf110_result"] || c.json; } catch(e) {}
  try { const c = $('Capture CWF-120 Result').first(); if (c) acc["cwf120_result"] = c.json["cwf120_result"] || c.json; } catch(e) {}
  try { const c = $('Capture CWF-130 Result').first(); if (c) acc["cwf130_result"] = c.json["cwf130_result"] || c.json; } catch(e) {}

// Add this node's capture
acc["cwf140_result"] = {
  status: subOutput.status || 'SUCCESS',
  payload: subOutput.payload || subOutput,
  captured_at: new Date().toISOString()
};

return [{ json: acc }];

// Phase-2 chain validation: pass if all children returned SUCCESS/COMPLETED.
// Deeper field validation (e.g. research_synthesis_finalized) is deferred to Phase 3 (state persistence)
// and Phase 5 (Ollama-backed real outputs).
const childResults = {
  CWF_110: $json.cwf110_result,
  CWF_120: $json.cwf120_result,
  CWF_130: $json.cwf130_result,
  CWF_140: $json.cwf140_result
};
const allHealthy = Object.values(childResults).every(r => r && (r.status === 'SUCCESS' || r.status === 'COMPLETED'));
const topicFinalized = $json.cwf140_result && $json.cwf140_result.payload && $json.cwf140_result.payload.research_synthesis_finalized === true;
const validationOk = allHealthy; // Phase-2 acceptance: chain healthy is enough
return [{ json: { ...$json, pack_validation: { child_results_aggregated: childResults, all_children_healthy: allHealthy, topic_finalized: topicFinalized, validation_ok: validationOk, route_to_error: !validationOk, phase2_acceptance: 'chain_healthy_required' } } }];

if ($json.pack_validation.route_to_error) return [];
return [{
  json: {
    ...$json,
    dossier_write: {
      mutation_type: 'namespace_update',
      target: 'dossier.discovery',
      timestamp: new Date().toISOString(),
      writer_id: 'WF-100',
      pack_context: $json.pack_context,
      child_results: $json.pack_validation.child_results_aggregated,
      audit_entry: 'topic-intelligence-pack-completion from WF-100'
    }
  }
}];

if ($json.pack_validation.route_to_error) return [];
return [{
  json: {
    ...$json,
    se_route_runs_write: {
      operation: 'record_pack_execution',
      pack_id: 'WF-100',
      dossier_id: $json.dossier_id,
      child_workflows_executed: ['CWF-110', 'CWF-120', 'CWF-130', 'CWF-140'],
      execution_status: 'COMPLETED',
      topic_finalized: $json.pack_validation.topic_finalized,
      timestamp: new Date().toISOString()
    }
  }
}];

if ($json.pack_validation.route_to_error) return [];
const fs = require('fs');
const path = require('path');

const now = new Date().toISOString();
const completion_packet = {
  instance_id: 'WF-100-COMP-' + Date.now(),
  artifact_family: 'topic_intelligence_result',
  schema_version: '1.0.0',
  producer_workflow: 'WF-100',
  dossier_ref: $json.dossier_id,
  created_at: now,
  status: 'CREATED',
  payload: {
    pack_executed: 'WF-100',
    topic_finalized: $json.pack_validation.topic_finalized,
    next_workflow: 'WF-200',
    child_packets: ["CWF-110_output","CWF-120_output","CWF-130_output","CWF-140_output"]
  }
};

const repoRoot = 'C:/ShadowEmpire-Git';
const dataDir = path.join(repoRoot, 'data');
const packetIndexPath = path.join(dataDir, 'se_packet_index.json');
if (!fs.existsSync(dataDir)) fs.mkdirSync(dataDir, { recursive: true });

let index = { entries: [], total_entries: 0, last_updated: now };
if (fs.existsSync(packetIndexPath)) {
  const parsed = JSON.parse(fs.readFileSync(packetIndexPath, 'utf8'));
  index = {
    ...index,
    ...parsed,
    entries: Array.isArray(parsed.entries)
      ? parsed.entries
      : (Array.isArray(parsed.packets) ? parsed.packets : [])
  };
}

index.entries.push({
  packet_id: completion_packet.instance_id,
  instance_id: completion_packet.instance_id,
  artifact_family: completion_packet.artifact_family,
  schema_version: completion_packet.schema_version,
  producer_workflow: completion_packet.producer_workflow,
  dossier_ref: completion_packet.dossier_ref,
  created_at: completion_packet.created_at,
  status: completion_packet.status,
  payload: completion_packet.payload
});
index.total_entries = index.entries.length;
index.last_updated = now;

fs.writeFileSync(packetIndexPath, JSON.stringify(index, null, 2), 'utf8');

return [{
  json: {
    workflow_id: 'WF-100',
    execution_status: 'SUCCESS',
    completion_packet,
    packet_persistence: {
      packet_index_path: packetIndexPath,
      packet_entries: index.entries.length,
      persisted_at: now
    }
  }
}];

if (!$json.pack_validation.route_to_error) return [];
return [{
  json: {
    workflow_id: 'WF-100',
    routing_decision: 'ERROR',
    route_to_workflow: 'WF-900',
    error_message: 'Pack validation failed or child workflow failed',
    failure_context: $json.pack_validation,
    child_results: $json.pack_validation.child_results_aggregated
  }
}];
